mapper.select:
SELECT s.id, s.dog_id AS dogId, s.title, s.schedule_date AS scheduleDate, s.schedule_type_code AS scheduleTypeCode, s.is_completed AS isCompleted, s.memo FROM public.schedules s JOIN public.dogs d ON s.dog_id = d.id WHERE d.user_id = #{userId}
AND s.dog_id = #{dogId}
AND s.schedule_type_code = #{type}
AND (s.title LIKE '%' || #{keyword} || '%' OR s.memo LIKE '%' || #{keyword} || '%')
AND s.schedule_date >= CAST(#{startDate} AS TIMESTAMP)
AND s.schedule_date <= CAST(#{endDate} || ' 23:59:59' AS TIMESTAMP)
ORDER BY s.schedule_date ASC
